// ── Day tracking ──────────────────────────────────────────────────────────────
// Count Monday–Friday days between two UTC dates (end is exclusive).
function countWeekdays(startDate, endDate) {
  let count = 0;
  const current = new Date(startDate);
  current.setUTCHours(0, 0, 0, 0);
  const end = new Date(endDate);
  end.setUTCHours(0, 0, 0, 0);

  while (current < end) {
    const dow = current.getUTCDay();
    if (dow !== 0 && dow !== 6) count++;
    current.setUTCDate(current.getUTCDate() + 1);
  }
  return count;
}

function getTodayIndex() {
  const start = new Date(process.env.START_DATE);
  const today = new Date();
  today.setUTCHours(0, 0, 0, 0);
  const elapsed = countWeekdays(start, today);
  return elapsed % DAYS.length;
}

// ── Email HTML ────────────────────────────────────────────────────────────────
function buildEmail(day, dayNumber, total) {
  const { domain, taskCode, concept, research, application, questions } = day;

  const bodyParagraphs = concept.body
    .split("\n\n")
    .map(
      (p) =>
        `<p style="margin:0 0 14px;line-height:1.7;color:#333;">${p}</p>`
    )
    .join("");

  const questionsHtml = questions
    .map((q, i) => {
      const optionsHtml = q.options
        .map((opt) => {
          const isCorrect = opt.charAt(0) === q.answer;
          return `<li style="margin:6px 0;color:${isCorrect ? "#2a6e2a" : "#333"};font-weight:${isCorrect ? "bold" : "normal"};">${isCorrect ? "✓ " : ""}${opt}</li>`;
        })
        .join("");

      return `
        <div style="margin-bottom:24px;">
          <p style="margin:0 0 10px;font-weight:bold;color:#333;">${i + 1}. ${q.q}</p>
          <ul style="margin:0 0 10px;padding-left:20px;list-style:none;">${optionsHtml}</ul>
          <p style="margin:0;font-style:italic;color:#555;font-size:14px;"><strong>Rationale:</strong> ${q.rationale}</p>
        </div>`;
    })
    .join("");

  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width,initial-scale=1">
</head>
<body style="margin:0;padding:24px;background:#e8e3db;font-family:Georgia,serif;">
  <div style="max-width:620px;margin:0 auto;background:#f8f5f0;border-radius:8px;overflow:hidden;">

    <!-- Header -->
    <div style="background:#c8440a;padding:20px 28px;">
      <p style="margin:0;color:#fff;font-size:13px;letter-spacing:0.05em;">
        BCBA Daily Brief &nbsp;&middot;&nbsp; Day ${dayNumber} of ${total} &nbsp;&middot;&nbsp; ${domain} &nbsp;&middot;&nbsp; ${taskCode}
      </p>
    </div>

    <!-- Body -->
    <div style="padding:28px;">

      <!-- Concept -->
      <h2 style="margin:0 0 16px;color:#c8440a;font-size:20px;">${concept.title}</h2>
      ${bodyParagraphs}

      <!-- Research Citation -->
      <div style="margin:24px 0;padding:16px;background:#fff;border-left:4px solid #c8440a;border-radius:0 4px 4px 0;">
        <p style="margin:0 0 10px;font-style:italic;color:#c8440a;font-size:14px;">${research.citation}</p>
        <p style="margin:0;line-height:1.7;color:#333;">${research.summary}</p>
      </div>

      <!-- Clinical Application -->
      <h3 style="margin:24px 0 12px;color:#c8440a;font-size:16px;">Clinical Application</h3>
      <p style="margin:0 0 24px;line-height:1.7;color:#333;">${application}</p>

      <!-- Practice Questions -->
      <h3 style="margin:0 0 16px;color:#c8440a;font-size:16px;">Practice Questions</h3>
      ${questionsHtml}

    </div>

    <!-- Footer -->
    <div style="padding:16px 28px;background:#e0dbd3;border-top:1px solid #cec8c0;">
      <p style="margin:0;font-size:12px;color:#777;">
        Day ${dayNumber} &nbsp;&middot;&nbsp; ben@voxprint.com &nbsp;&middot;&nbsp; Reply STOP to unsubscribe
      </p>
    </div>

  </div>
</body>
</html>`;
}

// ── Route handler ─────────────────────────────────────────────────────────────
export async function GET(req) {
  // Verify Vercel's cron secret.
  if (
    req.headers.get("authorization") !==
    "Bearer " + process.env.CRON_SECRET
  ) {
    return new Response("Unauthorized", { status: 401 });
  }

  const index = getTodayIndex();
  const day = DAYS[index];
  const dayNumber = index + 1;

  const html = buildEmail(day, dayNumber, DAYS.length);

  const { error } = await resend.emails.send({
    from: "BCBA Daily Brief <onboarding@resend.dev>",
    to: "ben@voxprint.com",
    subject: `BCBA Daily Brief — Day ${dayNumber}: ${day.concept.title}`,
    html,
  });

  if (error) {
    console.error("Resend error:", error);
    return new Response("Email send failed", { status: 500 });
  }

  return new Response(
    JSON.stringify({ ok: true, day: dayNumber, concept: day.concept.title }),
    { status: 200, headers: { "Content-Type": "application/json" } }
  );
}
